import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  ERROR_CROSS,
  ERROR_EXCEED_NUMBER,
  ERROR_MAX_PER_PAIR,
  ERROR_NON_ADJACENT,
  areAdjacent,
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function px(n) {
  return n * GRID;
}

function findIslandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y);
}

function islandById(islands, id) {
  return islands.find((i) => i.id === id);
}

function getNeighborInDirection(islands, from, dir) {
  // returns nearest island in that direction (ignores bridges)
  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      if (!best || isl.x > best.x) best = isl;
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      if (!best || isl.x < best.x) best = isl;
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      if (!best || isl.y > best.y) best = isl;
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      if (!best || isl.y < best.y) best = isl;
    }
  }
  return best;
}

function bridgeLinesForKey(key, count) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  const a = { x: x1, y: y1 };
  const b = { x: x2, y: y2 };
  const x1p = px(a.x);
  const y1p = px(a.y);
  const x2p = px(b.x);
  const y2p = px(b.y);

  const isH = a.y === b.y;
  const offset = 6; // pixel offset for double bridges

  if (count === 1) {
    return [
      {
        x1: x1p,
        y1: y1p,
        x2: x2p,
        y2: y2p,
      },
    ];
  }
  if (count === 2) {
    if (isH) {
      return [
        { x1: x1p, y1: y1p - offset, x2: x2p, y2: y2p - offset },
        { x1: x1p, y1: y1p + offset, x2: x2p, y2: y2p + offset },
      ];
    }
    return [
      { x1: x1p - offset, y1: y1p, x2: x2p - offset, y2: y2p },
      { x1: x1p + offset, y1: y1p, x2: x2p + offset, y2: y2p },
    ];
  }
  return [];
}

export default function App() {
  const [puzzleName, setPuzzleName] = useState('Easy');
  const puzzle = useMemo(() => puzzles.find((p) => p.name === puzzleName) ?? puzzles[0], [puzzleName]);
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(islands[0]?.id ?? 0);
  const [pendingFromId, setPendingFromId] = useState(null); // keyboard selection
  const [pendingDir, setPendingDir] = useState(null); // last arrow dir while pending
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  useEffect(() => {
    // puzzle change: reset everything
    setBridges(new Map());
    setSelectedId(null);
    setPendingFromId(null);
    setPendingDir(null);
    setError(null);
    setCursorId(puzzle.islands[0]?.id ?? 0);
  }, [puzzleName]);

  useEffect(() => {
    // keep cursor valid if puzzle changes
    if (!islandById(islands, cursorId)) {
      setCursorId(islands[0]?.id ?? 0);
    }
  }, [islands, cursorId]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValid(result) {
    if (result?.valid) setError(null);
  }

  function setErrorIfAny(result) {
    if (!result?.valid && result?.error) setError(result.error);
  }

  function cycleBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    const next = (current + 1) % 3; // 0->1->2->0

    if (next === 0) {
      const nb = new Map(bridges);
      nb.delete(key);
      setBridges(nb);
      setError(null);
      return;
    }

    const delta = next - current;
    const check = canAddBridge(islands, bridges, from, to, delta);
    if (!check.valid) {
      setErrorIfAny(check);
      return;
    }

    const nb = new Map(bridges);
    nb.set(key, next);
    setBridges(nb);
    clearErrorOnValid(check);
  }

  function removeBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    if (!(bridges.get(key) > 0)) return;
    const nb = new Map(bridges);
    nb.delete(key);
    setBridges(nb);
    setError(null);
  }

  function onIslandClick(isl, e) {
    // ctrl+click removes a bridge if selection exists and this island is the other endpoint
    if ((e.ctrlKey || e.metaKey) && selectedId !== null && selectedId !== isl.id) {
      const from = islandById(islands, selectedId);
      if (from && areAdjacent(islands, from, isl, bridges)) {
        removeBridge(from, isl);
      }
      setSelectedId(null);
      return;
    }

    if (selectedId === null) {
      setSelectedId(isl.id);
      setCursorId(isl.id);
      return;
    }

    if (selectedId === isl.id) {
      // clicking same island keeps selection
      return;
    }

    const from = islandById(islands, selectedId);
    const to = isl;
    if (!from) {
      setSelectedId(null);
      return;
    }

    if (!areAdjacent(islands, from, to, bridges)) {
      setError(ERROR_NON_ADJACENT);
      setSelectedId(null);
      return;
    }

    cycleBridge(from, to);
    setSelectedId(null);
  }

  function onIslandContextMenu(isl, e) {
    e.preventDefault();
    if (selectedId === null || selectedId === isl.id) return;
    const from = islandById(islands, selectedId);
    if (!from) return;
    if (!areAdjacent(islands, from, isl, bridges)) return;
    removeBridge(from, isl);
    setSelectedId(null);
  }

  function handleKeyDown(e) {
    const cur = islandById(islands, cursorId) ?? islands[0];
    if (!cur) return;

    if (e.key === 'Escape') {
      setPendingFromId(null);
      setPendingDir(null);
      setSelectedId(null);
      setError(null);
      return;
    }

    const dirFromKey =
      e.key === 'ArrowLeft'
        ? 'left'
        : e.key === 'ArrowRight'
          ? 'right'
          : e.key === 'ArrowUp'
            ? 'up'
            : e.key === 'ArrowDown'
              ? 'down'
              : null;

    if (dirFromKey) {
      e.preventDefault();
      const nxt = getNeighborInDirection(islands, cur, dirFromKey);
      if (nxt) {
        setCursorId(nxt.id);
        if (pendingFromId !== null) setPendingDir(dirFromKey);
      }
      return;
    }

    if (e.key === 'Enter') {
      e.preventDefault();

      if (pendingFromId === null) {
        setPendingFromId(cur.id);
        setSelectedId(cur.id);
        setPendingDir(null);
        return;
      }

      // second enter: toggle bridge from pendingFromId to current cursor target
      const from = islandById(islands, pendingFromId);
      const to = cur;

      if (!from || !to || from.id === to.id) {
        setPendingFromId(null);
        setPendingDir(null);
        setSelectedId(null);
        return;
      }

      if (!areAdjacent(islands, from, to, bridges)) {
        setError(ERROR_NON_ADJACENT);
        setPendingFromId(null);
        setPendingDir(null);
        setSelectedId(null);
        return;
      }

      cycleBridge(from, to);
      setPendingFromId(null);
      setPendingDir(null);
      setSelectedId(null);
      return;
    }

    // Backspace/Delete removes existing bridge between pending and current
    if (e.key === 'Backspace' || e.key === 'Delete') {
      if (pendingFromId === null) return;
      const from = islandById(islands, pendingFromId);
      const to = cur;
      if (from && to && from.id !== to.id && areAdjacent(islands, from, to, bridges)) {
        removeBridge(from, to);
      }
      setPendingFromId(null);
      setPendingDir(null);
      setSelectedId(null);
    }
  }

  const bridgeLineEls = [];
  for (const [k, n] of bridges.entries()) {
    if (n <= 0) continue;
    const segments = bridgeLinesForKey(k, n);
    for (let i = 0; i < segments.length; i++) {
      const s = segments[i];
      bridgeLineEls.push(
        <line
          key={`${k}:${i}`}
          x1={s.x1}
          y1={s.y1}
          x2={s.x2}
          y2={s.y2}
          stroke="#0f0"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
    }
  }

  return (
    <div className="app-root" tabIndex={0} onKeyDown={handleKeyDown}>
      <div className="ui-bar">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleName}
            onChange={(e) => setPuzzleName(e.target.value)}
            aria-label="Puzzle"
          >
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button
          onClick={() => {
            setBridges(new Map());
            setSelectedId(null);
            setPendingFromId(null);
            setPendingDir(null);
            setError(null);
          }}
        >
          Reset
        </button>
        <span className="counts-readout">
          {islands.map((i) => `${i.id}:${counts.get(i.id) ?? 0}/${i.value}`).join('  ')}
        </span>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        width={SVG_W}
        height={SVG_H}
        className="board"
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
      >
        {bridgeLineEls}

        {/* cursor (must not be a circle) */}
        {(() => {
          const cur = islandById(islands, cursorId);
          if (!cur) return null;
          const size = 26;
          return (
            <rect
              className="cursor"
              x={px(cur.x) - size / 2}
              y={px(cur.y) - size / 2}
              width={size}
              height={size}
              fill="none"
              stroke={pendingFromId !== null ? '#0ff' : '#0f0'}
              strokeWidth={2}
            />
          );
        })()}

        {islands.map((isl) => {
          const r = 16;
          const isSelected = selectedId === isl.id;
          return (
            <g
              key={isl.id}
              onClick={(e) => onIslandClick(isl, e)}
              onContextMenu={(e) => onIslandContextMenu(isl, e)}
              style={{ cursor: 'pointer' }}
            >
              <circle
                cx={px(isl.x)}
                cy={px(isl.y)}
                r={r}
                fill={isSelected ? '#0f0' : 'black'}
                stroke="#0f0"
                strokeWidth={3}
              />
              <text
                x={px(isl.x)}
                y={px(isl.y) + 6}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={18}
                fill={isSelected ? 'black' : '#0f0'}
              >
                {isl.value}
              </text>
            </g>
          );
        })}
      </svg>

      <div className="help">
        Mouse: click two adjacent islands to cycle none→single→double→none. Right-click or Ctrl+click removes.
        Keyboard: arrows move cursor, Enter selects then Enter toggles, Esc cancels.
      </div>
    </div>
  );
}
