    if (!(bridges.get(key) > 0)) return;
    const nb = new Map(bridges);
    nb.delete(key);
    setBridges(nb);
    setError(null);
  }

  function onIslandClick(isl, e) {
    if ((e.ctrlKey || e.metaKey) && selectedId !== null && selectedId !== isl.id) {
      const from = islandById(islands, selectedId);
      if (from && areAdjacent(islands, from, isl, bridges)) removeBridge(from, isl);
      setSelectedId(null);
      return;
    }

    if (selectedId === null) {
      setSelectedId(isl.id);
      setCursorId(isl.id);
      return;
    }

    if (selectedId === isl.id) return;

    const from = islandById(islands, selectedId);
    if (!from) {
      setSelectedId(null);
      return;
    }

    if (!areAdjacent(islands, from, isl, bridges)) {
      setError(ERROR_NON_ADJACENT);
      setSelectedId(null);
      return;
    }

    cycleBridge(from, isl);
    setSelectedId(null);
  }

  function onIslandContextMenu(isl, e) {
    e.preventDefault();
    if (selectedId === null || selectedId === isl.id) return;
    const from = islandById(islands, selectedId);
    if (from && areAdjacent(islands, from, isl, bridges)) removeBridge(from, isl);
    setSelectedId(null);
  }

  function handleKeyDown(e) {
    const cur = islandById(islands, cursorId) ?? islands[0];
    if (!cur) return;

    if (e.key === 'Escape') {
      setPendingFromId(null);
      setSelectedId(null);
      setError(null);
      return;
    }

    const dir =
      e.key === 'ArrowLeft'
        ? 'left'
        : e.key === 'ArrowRight'
          ? 'right'
          : e.key === 'ArrowUp'
            ? 'up'
            : e.key === 'ArrowDown'
              ? 'down'
              : null;

    if (dir) {
      e.preventDefault();
      const nxt = getNeighborInDirection(islands, cur, dir);
      if (nxt) setCursorId(nxt.id);
      return;
    }

    if (e.key === 'Enter') {
      e.preventDefault();
      if (pendingFromId === null) {
        setPendingFromId(cur.id);
        setSelectedId(cur.id);
        return;
      }

      const from = islandById(islands, pendingFromId);
      const to = cur;
      if (!from || !to || from.id === to.id) {
        setPendingFromId(null);
        setSelectedId(null);
        return;
      }

      if (!areAdjacent(islands, from, to, bridges)) {
        setError(ERROR_NON_ADJACENT);
        setPendingFromId(null);
        setSelectedId(null);
        return;
      }

      cycleBridge(from, to);
      setPendingFromId(null);
      setSelectedId(null);
    }
  }

  const bridgeLineEls = [];
  for (const [k, n] of bridges.entries()) {
    if (n <= 0) continue;
    const segments = bridgeLinesForKey(k, n);
    for (let i = 0; i < segments.length; i++) {
      const s = segments[i];
      bridgeLineEls.push(
        <line
          key={`${k}:${i}`}
          x1={s.x1}
          y1={s.y1}
          x2={s.x2}
          y2={s.y2}
          stroke="#0f0"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
    }
  }

  return (
    <div className="app-root" tabIndex={0} onKeyDown={handleKeyDown} ref={rootRef}>
      <div className="ui-bar">
        <label>
          Puzzle:{' '}
          <select value={puzzleName} onChange={(e) => setPuzzleName(e.target.value)}>
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button
          onClick={() => {
            setBridges(new Map());
            setSelectedId(null);
            setPendingFromId(null);
            setError(null);
          }}
        >
          Reset
        </button>
        <span className="counts-readout">
          {islands.map((i) => `${i.id}:${counts.get(i.id) ?? 0}/${i.value}`).join('  ')}
        </span>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg width={SVG_W} height={SVG_H} className="board" viewBox={`0 0 ${SVG_W} ${SVG_H}`}>
        {bridgeLineEls}

        {/* keyboard cursor (not a circle) */}
        {(() => {
          const cur = islandById(islands, cursorId);
          if (!cur) return null;
          const size = 26;
          return (
            <rect
              className="cursor"
              x={px(cur.x) - size / 2}
              y={px(cur.y) - size / 2}
              width={size}
              height={size}
              fill="none"
              stroke={pendingFromId !== null ? '#0ff' : '#0f0'}
              strokeWidth={2}
            />
          );
        })()}

        {islands.map((isl) => {
          const isSelected = selectedId === isl.id;
          return (
            <g
              key={isl.id}
              onClick={(e) => onIslandClick(isl, e)}
              onContextMenu={(e) => onIslandContextMenu(isl, e)}
              style={{ cursor: 'pointer' }}
            >
              <circle
                cx={px(isl.x)}
                cy={px(isl.y)}
                r={16}
                fill={isSelected ? '#0f0' : 'black'}
                stroke="#0f0"
                strokeWidth={3}
              />
              <text
                x={px(isl.x)}
                y={px(isl.y) + 6}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={18}
                fill={isSelected ? 'black' : '#0f0'}
              >
                {isl.value}
              </text>
            </g>
          );
        })}
      </svg>

      <div className="help">
        Mouse: click two adjacent islands to cycle none→single→double→none. Right-click or Ctrl+click removes.
        Keyboard: arrows move cursor, Enter selects then Enter toggles, Esc cancels.
      </div>
    </div>
  );
}
