export const ERROR_NON_ADJACENT = 'Cannot connect non-adjacent islands';
export const ERROR_MAX_PER_PAIR = 'Max 2 bridges per pair';
export const ERROR_EXCEED_NUMBER = 'Island would exceed its number';
export const ERROR_CROSS = 'Bridges would cross';

export function canonicalBridgeKey(a, b) {
  const p1 = { x: a.x, y: a.y };
  const p2 = { x: b.x, y: b.y };
  const first = p1.x < p2.x || (p1.x === p2.x && p1.y <= p2.y) ? p1 : p2;
  const second = first === p1 ? p2 : p1;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

function isHorizontal(a, b) {
  return a.y === b.y && a.x !== b.x;
}
function isVertical(a, b) {
  return a.x === b.x && a.y !== b.y;
}

export function areAdjacent(islands, from, to, bridges) {
  if (!from || !to) return false;
  if (!(isHorizontal(from, to) || isVertical(from, to))) return false;

  // must have clear path: no island between
  if (isHorizontal(from, to)) {
    const y = from.y;
    const minX = Math.min(from.x, to.x);
    const maxX = Math.max(from.x, to.x);
    const between = islands.some((i) => i.id !== from.id && i.id !== to.id && i.y === y && i.x > minX && i.x < maxX);
    if (between) return false;
  } else {
    const x = from.x;
    const minY = Math.min(from.y, to.y);
    const maxY = Math.max(from.y, to.y);
    const between = islands.some((i) => i.id !== from.id && i.id !== to.id && i.x === x && i.y > minY && i.y < maxY);
    if (between) return false;
  }

  // cannot cross existing bridge
  const key = canonicalBridgeKey(from, to);
  for (const [k, count] of bridges.entries()) {
    if (count <= 0) continue;
    if (k === key) continue;
    const [x1, y1, x2, y2] = k.split(',').map(Number);
    const A = { x: x1, y: y1 };
    const B = { x: x2, y: y2 };

    if (isHorizontal(from, to) && A.x === B.x) {
      const cxMin = Math.min(from.x, to.x);
      const cxMax = Math.max(from.x, to.x);
      const byMin = Math.min(A.y, B.y);
      const byMax = Math.max(A.y, B.y);
      if (A.x > cxMin && A.x < cxMax && from.y > byMin && from.y < byMax) return false;
    }
    if (isVertical(from, to) && A.y === B.y) {
      const cyMin = Math.min(from.y, to.y);
      const cyMax = Math.max(from.y, to.y);
      const bxMin = Math.min(A.x, B.x);
      const bxMax = Math.max(A.x, B.x);
      if (from.x > bxMin && from.x < bxMax && A.y > cyMin && A.y < cyMax) return false;
    }
  }

  return true;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);
  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = k.split(',').map(Number);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }
  return counts;
}

function segmentsCross(k1, k2) {
  const [x1, y1, x2, y2] = k1.split(',').map(Number);
  const [x3, y3, x4, y4] = k2.split(',').map(Number);

  // ignore if share endpoints
  const endpoints1 = [`${x1},${y1}`, `${x2},${y2}`];
  const endpoints2 = [`${x3},${y3}`, `${x4},${y4}`];
  if (endpoints1.some((e) => endpoints2.includes(e))) return false;

  const h1 = y1 === y2;
  const v1 = x1 === x2;
  const h2 = y3 === y4;
  const v2 = x3 === x4;
  if (!(h1 || v1) || !(h2 || v2)) return false;
  if ((h1 && h2) || (v1 && v2)) return false;

  const hx = h1 ? [Math.min(x1, x2), Math.max(x1, x2), y1] : [Math.min(x3, x4), Math.max(x3, x4), y3];
  const vy = v1 ? [Math.min(y1, y2), Math.max(y1, y2), x1] : [Math.min(y3, y4), Math.max(y3, y4), x3];
  const [hMinX, hMaxX, hy] = hx;
  const [vMinY, vMaxY, vx] = vy;
  return vx > hMinX && vx < hMaxX && hy > vMinY && hy < vMaxY;
}

export function bridgesCross(bridges) {
  const keys = [];
  for (const [k, n] of bridges.entries()) if (n > 0) keys.push(k);
  for (let i = 0; i < keys.length; i++) {
    for (let j = i + 1; j < keys.length; j++) {
      if (segmentsCross(keys[i], keys[j])) return true;
    }
  }
  return false;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to || from.id === to.id) return { valid: false, error: ERROR_NON_ADJACENT };
  if (!(isHorizontal(from, to) || isVertical(from, to))) return { valid: false, error: ERROR_NON_ADJACENT };
  if (!areAdjacent(islands, from, to, bridges)) return { valid: false, error: ERROR_NON_ADJACENT };

  const key = canonicalBridgeKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = current + delta;
  if (next > 2) return { valid: false, error: ERROR_MAX_PER_PAIR };
  if (next < 0) return { valid: false, error: ERROR_MAX_PER_PAIR };

  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = (counts.get(from.id) ?? 0) + delta;
  const toCount = (counts.get(to.id) ?? 0) + delta;
  if (fromCount > from.value || toCount > to.value) return { valid: false, error: ERROR_EXCEED_NUMBER };

  if (delta > 0 && current === 0) {
    const tmp = new Map(bridges);
    tmp.set(key, 1);
    if (bridgesCross(tmp)) return { valid: false, error: ERROR_CROSS };
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;
  const coordToId = new Map(islands.map((i) => [`${i.x},${i.y}`, i.id]));
  const adj = new Map(islands.map((i) => [i.id, []]));

  for (const [k, n] of bridges.entries()) {
    if (n <= 0) continue;
    const [x1, y1, x2, y2] = k.split(',').map(Number);
    const a = coordToId.get(`${x1},${y1}`);
    const b = coordToId.get(`${x2},${y2}`);
    if (a === undefined || b === undefined) continue;
    adj.get(a).push(b);
    adj.get(b).push(a);
  }

  const startId = islands[0].id;
  const seen = new Set([startId]);
  const q = [startId];
  while (q.length) {
    const cur = q.shift();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        q.push(nxt);
      }
    }
  }
  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }
  if (bridgesCross(bridges)) return false;
  if (!checkConnectivity(islands, bridges)) return false;
  return true;
}
